// Build a single run-summary item. On a clean sweep the Postgres node
// emits one empty item (alwaysOutputData), so filter to real remediations.
const rows = $input.all().map(i => i.json).filter(r => r && r.document_id);
const init = $('Initialize').first().json;
return [{ json: {
  workflow_id: 'SW-016',
  correlation_id: init.correlation_id,
  started_at: init.started_at,
  stale_minutes: init.staleMinutes,
  batch_limit: init.batchLimit,
  remediated_count: rows.length,
  remediated: rows
} }];
